INSERT INTO community_post (
    board_id, author_id, title, summary, content, badge, status,
    is_featured, is_pinned, view_count, comment_count, favorite_count, like_count,
    is_ai_generated, gallery_images, published_at
) VALUES (
    #{boardId}, #{authorId}, #{title}, #{summary}, #{content}, #{badge}, #{status},
    #{featured}, #{pinned}, #{viewCount}, #{commentCount}, #{favoriteCount}, #{likeCount},
    #{isAiGenerated}, #{galleryImages}, #{publishedAt}
)

mapper.select:
SELECT FROM community_post p LEFT JOIN community_board b ON b.id = p.board_id LEFT JOIN user_account u ON u.id = p.author_id WHERE p.status = 1 AND p.board_id = #{boardId}
ORDER BY (p.view_count * 1 + p.comment_count * 5 + p.favorite_count * 3 + p.like_count * 2) DESC, p.published_at DESC
ORDER BY p.is_featured DESC, p.is_pinned DESC, p.published_at DESC, p.id DESC
ORDER BY p.is_pinned DESC, p.published_at DESC, p.id DESC
LIMIT #{limit} OFFSET #{offset}
